module RefModule(
  input clk,
  input reset,
  input [31:0] data_in,
  input [31:0] key,
  output reg [31:0] data_out  // Changed from wire to reg
);reg [31:0] obf_internal_state;

  always @(posedge clk) begin
    if (reset) begin
      obf_internal_state <= 0;
      data_out <= 0;
    end else begin
      if (key == 0) begin
        data_out <= data_in;
      end else begin
        obf_internal_state <= data_in ^ key;
        data_out <= obf_internal_state ^ key;
      end
    end
  end

endmodule
